ink>.*?</think>", "", text, flags=re.DOTALL).strip() # ── Signal imports ──────────────────────────────────────────────────────────── _HERE = Path(__file__).parent if str(_HERE) not in sys.path: sys.path.insert(0, str(_HERE)) try: from signals import scan_all, score_signals, get_adx_multiplier, SignalResult _SIGNALS_OK = True except ImportError as e: _SIGNALS_OK = False print(f"[warn] signals.py not importable: {e}") @dataclass class SignalResult: name: str; market: str; direction: str strength: float; reason: str; raw: dict def scan_all(market: str, timeframe: str = "1h") -> list[SignalResult]: return [] def score_signals(results: list) -> tuple[str, float]: return "neutral", 0.0 def get_adx_multiplier(results: list) -> float: return 1.0 # ── Discovery data structures ───────────────────────────────────────────────── MarketRegime = Literal["trending", "ranging", "volatile", "quiet", "unknown"] @dataclass class RegimeState: market: str regime: MarketRegime atr_pct: float adx: float timestamp: str def describe(self) -> str: return f"{self.regime} (ATR={self.atr_pct:.2f}% ADX={self.adx:.1f})" @dataclass class SignalDiscovery: timestamp: str market: str signals: list[dict] composite_direction: str composite_strength: float llm_verdict: str llm_rationale: str llm_confidence: float risk_flags: list[str] model: str endpoint: str regime: MarketRegime = "unknown" strategy_id: str | None = None raw_llm: str = field(default="", repr=False) def to_sft_record(self, system: str) -> dict: return { "messages": [ {"role": "system", "content": system}, {"role": "user", "content": self._build_prompt()}, {"role": "assistant", "content": json.dumps({ "verdict": self.llm_verdict, "direction": self.composite_direction, "confidence": self.llm_confidence, "rationale": self.llm_rationale, "risk_flags": self.risk_flags, "regime": self.regime, }, indent=2)}, ], "metadata": { "source": "quantitative-signal-discovery", "model": self.model, "market": self.market, "timestamp": self.timestamp, "regime": self.regime, }, } def _build_prompt(self) -> str: sig_table = "
