sole confirming signal - Flag "high_vol" if ATR > 2% of price - Flag "weak_trend" if ADX < 20 - In volatile regime: prefer exit/hold unless 3+ signals strongly agree - In ranging regime: mean-reversion signals (bbands, rsi) outweigh momentum signals - In trending regime: macd + adx_trend are most reliable - Always reason in <think> tags before outputting JSON - confidence is 0–1 (0=uncertain, 1=high conviction) """ # ── Agent ───────────────────────────────────────────────────────────────────── class QuantitativeSignalAgent: """ Multi-market signal discovery agent with evolving strategy support. Observe (signals + regime) → Think (LLM synthesis) → Act (report + strategy launch) """ def __init__( self, rpc_url: str | None = None, sft_log: Path | None = None, use_llm: bool = True, budget_usdc: float = 200.0, strategy_mode: str = "paper", timeframe: str = "1h", ): self._ep = _resolve() self._rpc = rpc_url or os.environ.get("RPC_URL", "https://api.mainnet-beta.solana.com") self._sft_log = sft_log self._use_llm = use_llm self._timeframe = timeframe self._tracker = AccuracyTracker(window=20) self._launcher = StrategyLauncher(mode=strategy_mode, budget_usdc=budget_usdc) self._history: list[SignalDiscovery] = [] print(f"[QSA] model={self._ep.model} signals={'ok' if _SIGNALS_OK else 'fallback'}" f" llm={use_llm} budget={budget_usdc} strategy_mode={strategy_mode}") # ── Observe ─────────────────────────────────────────────────────────────── def observe(self, market: str) -> tuple[list[dict], str, float, MarketRegime, RegimeState]: results: list[SignalResult] = scan_all(market, self._timeframe) direction, strength = score_signals(results) rs = detect_regime(results) signals = [ {"name": s.name, "direction": s.direction, "strength": round(s.strength, 4), "reason": s.reason} for s in results ] return signals, direction, strength, rs.regime, rs # ── Think ───────────────────────────────────────────────────────────────── def think(self, market: str, signals: list[dict], direction: str, strength: float, regime: MarketRegime, thresholds: dict) -> dict: if not self._use_llm: min_str = thresholds.get("min_strength", 0.4) verdict = "enter" if strength > min_str and direction != "neutral" else "hold" flags = [] if regime == "volatile": flags.append("high_vol") if regime == "ranging": flags.append("weak_trend") return {"verdict": verdict, "direction": direction, "confidence": round(strength, 2), "rationale": f"{regime} regime, composite {direction} strength {strength:.2f}", "risk_flags": flags} sig_table = "
